// Normalise for matching: lowercase, strip punctuation, collapse spaces
function norm(s) {
  return s.toLowerCase().replace(/[^а-яёa-z0-9\s]/gi, ' ').replace(/\s+/g, ' ').trim();
}

// Pre-build normalised index once
let _idx = null;
function idx() {
  if (!_idx) _idx = EXERCISE_BANK.map(e => ({ n: e.n, u: e.u, k: norm(e.n).split(' ') }));
  return _idx;
}

export function findExerciseUrl(name) {
  if (!name) return null;
  const q = norm(name);
  const qWords = q.split(' ').filter(w => w.length > 2);
  if (!qWords.length) return null;

  // 1. Exact normalised match
  for (const e of idx()) {
    if (norm(e.n) === q) return e.u;
  }

  // 2. All query words are contained in entry (query is a subset of entry words)
  //    Good for: "Подтягивания" → "Подтягивания обр. хватом"
  let subsetMatch = null, subsetLen = Infinity;
  for (const e of idx()) {
    if (qWords.every(w => e.k.includes(w))) {
      if (e.k.length < subsetLen) { subsetLen = e.k.length; subsetMatch = e.u; }
    }
  }
  if (subsetMatch) return subsetMatch;

  // 3. Best overlap score: shared meaningful words
  let best = null, bestScore = 0;
  for (const e of idx()) {
    const shared = qWords.filter(w => e.k.includes(w)).length;
    if (shared === 0) continue;
    const score = shared / Math.max(qWords.length, e.k.length);
    if (score > bestScore) { bestScore = score; best = e.u; }
  }
  // 33% threshold — catches singular/plural divergence and short names
  return bestScore >= 0.33 ? best : null;
}
